


<!DOCTYPE html PUBLIC "-//W3C//DTD XHTML 1.0" "http://www.w3.org/TR/xhtml1/DTD/xhtml1-transitional.dtd">
<html xmlns="http://www.w3.org/1999/xhtml" class="login-pf hydrated">

<head>
    <meta http-equiv="Content-Type" content="text/html; charset=UTF-8">
    <link rel="icon"
        href="data:image/svg+xml;base64,">

    <style data-styles="">
        gdt-devis-access,
        gdt-dropdown,
        gdt-tooltip,
        gdt-col,
        gdt-field-header,
        gdt-row,
        gdt-dropdown-custom,
        gdt-dropdown-native,
        gdt-card,
        gdt-price,
        gdt-dropdown-item,
        gdt-input-date,
        gdt-message,
        gdt-modal,
        gdt-push,
        gdt-button,
        gdt-checkbox,
        gdt-link,
        gdt-radio-button,
        gdt-tab-header,
        gdt-toggle,
        gdt-tab-content,
        gdt-tabs,
        gdt-textarea,
        gdt-input,
        gdt-title,
        gdt-action,
        gdt-button-icon,
        gdt-icon {
            visibility: hidden;
        }

        .hydrated {
            visibility: inherit;
        }
    </style>

    <meta http-equiv="X-UA-Compatible" content="IE=11">
    <meta name="robots" content="noindex, nofollow">
    <style>
        .gdt-field-header {
            display: block;
            line-height: var(--gdt-typo-text-line-height-lg);
            font-size: var(--gdt-typo-text-size-lg);
            font-weight: var(--gdt-typo-text-weight-regular);
            margin-bottom: var(--gdt-size-01);
        }

        .gdt-field-header__label {
            display: inline-flex;
            align-items: flex-end;
            gap: var(--gdt-size-icon-gap-lg);
            height: var(--gdt-typo-text-line-height-lg);
        }

        .gdt-field-header__optional {
            line-height: var(--gdt-typo-text-line-height-md);
            font-size: var(--gdt-typo-text-size-md);
            font-weight: var(--gdt-typo-text-weight-regular);
            color: var(--gdt-color-text-light);
            font-style: italic;
        }

        .gdt-field-header__description {
            line-height: var(--gdt-typo-text-line-height-md);
            font-size: var(--gdt-typo-text-size-md);
            font-weight: var(--gdt-typo-text-weight-regular);
            color: var(--gdt-color-text-light);
        }
    </style>
    <style>
        .gdt-tooltip {
            position: relative;
            display: inline-flex;
        }

        .gdt-tooltip.gdt-tooltip--inline {
            position: initial;
            display: inline;
        }

        .gdt-tooltip.gdt-tooltip--inline .gdt-tooltip__target {
            display: inline;
        }

        .gdt-tooltip.gdt-tooltip--hover .gdt-tooltip__target+.gdt-tooltip__overlay {
            display: none;
        }

        .gdt-tooltip.gdt-tooltip--hover .gdt-tooltip__target:hover+.gdt-tooltip__overlay {
            display: block;
        }

        .gdt-tooltip .gdt-tooltip__target {
            display: inline-flex;
            border-radius: var(--gdt-border-radius-component);
        }

        .gdt-tooltip .gdt-tooltip__target:focus-visible {
            outline: none;
        }

        .gdt-tooltip .gdt-tooltip__target:focus {
            box-shadow: var(--gdt-shadow-focus-default);
        }

        .gdt-tooltip .gdt-tooltip__target.gdt-tooltip__target--clickable:hover {
            cursor: pointer;
        }

        .gdt-tooltip .gdt-tooltip__overlay {
            display: none;
            cursor: initial;
            max-width: var(--gdt-tooltip-max-width);
            width: max-content;
            position: absolute;
            z-index: var(--gdt-z-index-tooltip);
            top: 0;
            left: 0;
            background: var(--gdt-color-base-dark-default);
            color: var(--gdt-color-base-dark-text-default);
            padding: var(--gdt-padding-base-md);
            border-radius: var(--gdt-border-radius-base);
        }

        .gdt-tooltip .gdt-tooltip__overlay .gdt-tooltip__overlay__arrow {
            position: absolute;
            background: var(--gdt-color-base-dark-default);
            width: var(--gdt-size-02);
            height: var(--gdt-size-02);
            transform: rotate(45deg);
        }

        .gdt-tooltip .gdt-tooltip__overlay.gdt-tooltip__overlay__bottom .gdt-tooltip__overlay__arrow {
            top: -4px;
        }

        .gdt-tooltip .gdt-tooltip__overlay.gdt-tooltip__overlay__top .gdt-tooltip__overlay__arrow {
            bottom: -4px;
        }

        .gdt-tooltip .gdt-tooltip__overlay.gdt-tooltip__overlay__right .gdt-tooltip__overlay__arrow {
            left: -4px;
        }

        .gdt-tooltip .gdt-tooltip__overlay.gdt-tooltip__overlay__left .gdt-tooltip__overlay__arrow {
            right: -4px;
        }
    </style>
    <style>
        .gdt-message {
            display: inline-flex;
            align-items: flex-start;
            gap: var(--gdt-size-02);
        }

        .gdt-message__text {
            margin: 0;
            flex: 1;
            line-height: var(--gdt-typo-text-line-height-md);
            font-size: var(--gdt-typo-text-size-md);
            font-weight: var(--gdt-typo-text-weight-regular);
        }

        .gdt-message__text sup {
            font-size: 65%;
            vertical-align: top;
            top: 0.1875em;
            line-height: initial;
        }

        .gdt-message.gdt-message--hidden {
            display: none;
        }

        .gdt-message.gdt-message--appearance-card {
            padding: var(--gdt-size-02);
        }

        .gdt-message.gdt-message--color-light {
            color: var(--gdt-color-text-light);
        }

        .gdt-message.gdt-message--color-light.gdt-message--appearance-card {
            background-color: var(--gdt-color-base-secondary-default);
        }

        .gdt-message.gdt-message--color-warning {
            color: var(--gdt-color-warning-default);
        }

        .gdt-message.gdt-message--color-warning.gdt-message--appearance-card {
            background-color: var(--gdt-color-warning-light-default);
        }

        .gdt-message.gdt-message--color-danger {
            color: var(--gdt-color-danger-default);
        }

        .gdt-message.gdt-message--color-danger.gdt-message--appearance-card {
            background-color: var(--gdt-color-danger-light-default);
        }

        .gdt-message.gdt-message--color-info {
            color: var(--gdt-color-info-default);
        }

        .gdt-message.gdt-message--color-info.gdt-message--appearance-card {
            background-color: var(--gdt-color-info-light-default);
        }

        .gdt-message.gdt-message--color-success {
            color: var(--gdt-color-success-default);
        }

        .gdt-message.gdt-message--color-success.gdt-message--appearance-card {
            background-color: var(--gdt-color-success-light-default);
        }

        .gdt-message.gdt-message--size-sm .gdt-message__text {
            margin: 0;
            line-height: var(--gdt-typo-text-line-height-sm);
            font-size: var(--gdt-typo-text-size-sm);
        }
    </style>
    <style>
        gdt-modal.gdt-modal {
            align-items: center;
            display: flex;
            height: 100%;
            width: 100%;
            justify-content: center;
            position: fixed;
            bottom: 0;
            left: 0;
            visibility: visible;
            z-index: 90;
            transition: visibility var(--gdt-transition-duration-medium);
        }

        @media (min-width: 420px) {
            gdt-modal.gdt-modal {
                top: 0;
                bottom: auto;
                margin: 0 auto;
            }
        }

        gdt-modal.gdt-modal .gdt-modal-overlay {
            position: fixed;
            width: 100%;
            bottom: 0;
            left: 0;
            right: 0;
            top: 0;
            background-color: var(--gdt-shadow-modal);
            transition: background-color var(--gdt-transition-duration-medium) ease-out;
        }

        gdt-modal.gdt-modal .gdt-modal__close {
            background-color: var(--gdt-color-white-default);
            border-radius: var(--gdt-border-radius-component);
            position: fixed;
            right: var(--gdt-padding-base-lg);
            top: var(--gdt-padding-base-lg);
        }

        gdt-modal.gdt-modal.gdt-modal--hidden {
            visibility: hidden;
        }

        gdt-modal.gdt-modal.gdt-modal--hidden .gdt-modal-overlay {
            background: transparent;
        }

        gdt-modal.gdt-modal.gdt-modal--hidden .gdt-modal-window {
            transform: translateY(30px);
        }

        @media (min-width: 420px) {
            gdt-modal.gdt-modal.gdt-modal--hidden .gdt-modal-window {
                transform: translateY(-30px);
            }
        }

        gdt-modal.gdt-modal .gdt-modal-window {
            box-shadow: var(--gdt-shadow-1);
            transform: translateY(0);
            width: 100%;
            position: fixed;
            bottom: 0;
            left: 0;
            transition: transform var(--gdt-transition-duration-medium) ease-out;
        }

        @media (min-width: 420px) {
            gdt-modal.gdt-modal .gdt-modal-window {
                margin: 48px;
                position: relative;
                max-width: var(--gdt-size-modal);
            }
        }

        gdt-modal.gdt-modal .gdt-modal-window.gdt-modal--fit-height-container {
            height: calc(100vh - 48px);
        }

        @media (min-width: 420px) {
            gdt-modal.gdt-modal .gdt-modal-window.gdt-modal--fit-height-container {
                height: calc(100vh - 96px);
            }
        }

        gdt-modal.gdt-modal .gdt-modal-window.gdt-modal--fit-height-container .gdt-modal-window__container {
            height: 100%;
        }

        gdt-modal.gdt-modal .gdt-modal-window.gdt-modal--fit-width-content {
            width: auto;
        }

        gdt-modal.gdt-modal .gdt-modal-window .gdt-modal-window__container {
            box-shadow: var(--gdt-shadow-1);
            border-radius: var(--gdt-border-radius-base) var(--gdt-border-radius-base) 0 0;
            background-color: var(--gdt-color-white-default);
            overflow: auto;
            box-sizing: border-box;
            display: flex;
            flex-direction: column;
            padding: var(--gdt-padding-base-lg);
            max-height: 100%;
        }

        @media (min-width: 420px) {
            gdt-modal.gdt-modal .gdt-modal-window .gdt-modal-window__container {
                max-width: var(--gdt-size-modal);
                border-radius: var(--gdt-border-radius-base);
            }
        }

        gdt-modal.gdt-modal .gdt-modal--color-secondary .gdt-modal-window__container {
            background-color: var(--gdt-color-base-secondary-default);
        }

        gdt-modal.gdt-modal .gdt-modal--color-secondary .gdt-modal__close {
            background-color: var(--gdt-color-base-secondary-default);
        }
    </style>
    <style>
        gdt-button {
            box-sizing: content-box;
            display: inline-flex;
        }

        gdt-button.gdt-button--fit-container {
            width: 100%;
        }

        gdt-button .gdt-button {
            flex: 1;
            display: inline-flex;
            justify-content: center;
            border-radius: var(--gdt-border-radius-component);
            border: none;
            outline: var(--gdt-border-regular) solid;
            outline-offset: var(--gdt-border-offset-regular);
            font-family: var(--gdt-typo-action-family);
            transition: color var(--gdt-transition-duration-short), background-color var(--gdt-transition-duration-short);
        }

        gdt-button .gdt-button:not(.gdt-button--disabled) {
            cursor: pointer;
        }

        gdt-button .gdt-button.gdt-button--disabled {
            opacity: var(--gdt-opacity-disabled);
        }

        gdt-button .gdt-button--appearance-primary {
            background-color: var(--gdt-color-control-primary-default);
            outline-color: var(--gdt-color-control-primary-default);
            color: var(--gdt-color-control-primary-text-default);
        }

        gdt-button .gdt-button--appearance-primary:hover:not(.gdt-button--disabled),
        gdt-button .gdt-button--appearance-primary:active:not(.gdt-button--disabled) {
            background-color: var(--gdt-color-control-primary-hover);
            outline-color: var(--gdt-color-control-primary-hover);
            color: var(--gdt-color-control-primary-text-hover);
        }

        gdt-button .gdt-button--appearance-secondary {
            background-color: var(--gdt-color-control-secondary-default);
            outline-color: var(--gdt-color-control-secondary-border-default);
            color: var(--gdt-color-control-secondary-text-default);
        }

        gdt-button .gdt-button--appearance-secondary:hover:not(.gdt-button--disabled),
        gdt-button .gdt-button--appearance-secondary:active:not(.gdt-button--disabled) {
            background-color: var(--gdt-color-control-secondary-hover);
            outline-color: var(--gdt-color-control-secondary-border-hover);
            color: var(--gdt-color-control-secondary-text-hover);
        }

        gdt-button .gdt-button .appearance-secondary-brand {
            --gdt-color-control-secondary-default: var(--gdt-color-accent-100);
        }

        gdt-button .gdt-button--appearance-tertiary {
            background-color: var(--gdt-color-control-tertiary-default);
            outline-color: var(--gdt-color-control-tertiary-border-default);
            color: var(--gdt-color-control-tertiary-text-default);
        }

        gdt-button .gdt-button--appearance-tertiary:hover:not(.gdt-button--disabled),
        gdt-button .gdt-button--appearance-tertiary:active:not(.gdt-button--disabled) {
            background-color: var(--gdt-color-control-tertiary-hover);
            outline-color: var(--gdt-color-control-tertiary-border-hover);
            color: var(--gdt-color-control-tertiary-text-hover);
        }

        gdt-button .gdt-button--appearance-primary-danger {
            background-color: var(--gdt-color-control-primary-danger-default);
            outline-color: var(--gdt-color-control-primary-danger-default);
            color: var(--gdt-color-control-primary-danger-text-default);
        }

        gdt-button .gdt-button--appearance-primary-danger:hover:not(.gdt-button--disabled),
        gdt-button .gdt-button--appearance-primary-danger:active:not(.gdt-button--disabled) {
            background-color: var(--gdt-color-control-primary-danger-hover);
            outline-color: var(--gdt-color-control-primary-danger-hover);
            color: var(--gdt-color-control-primary-danger-text-hover);
        }

        gdt-button .gdt-button--appearance-secondary-danger {
            background-color: var(--gdt-color-control-secondary-danger-default);
            outline-color: var(--gdt-color-control-secondary-danger-border-default);
            color: var(--gdt-color-control-secondary-danger-text-default);
        }

        gdt-button .gdt-button--appearance-secondary-danger:hover:not(.gdt-button--disabled),
        gdt-button .gdt-button--appearance-secondary-danger:active:not(.gdt-button--disabled) {
            background-color: var(--gdt-color-control-secondary-danger-hover);
            outline-color: var(--gdt-color-control-secondary-danger-border-hover);
            color: var(--gdt-color-control-secondary-danger-text-hover);
        }

        gdt-button .gdt-button--size-md {
            font-family: var(--gdt-typo-action-family);
            font-weight: var(--gdt-typo-action-weight-bold);
            font-size: var(--gdt-typo-action-size-md);
            line-height: var(--gdt-typo-action-line-height-md);
            min-width: var(--gdt-size-control-square-md);
            padding: var(--gdt-padding-control-md);
        }

        gdt-button .gdt-button--size-md.gdt-button--icon-left {
            padding: var(--gdt-padding-control-icon-left-md);
        }

        gdt-button .gdt-button--size-md.gdt-button--icon-right {
            padding: var(--gdt-padding-control-icon-right-md);
        }

        gdt-button .gdt-button--size-md.gdt-button--icon-left.gdt-button--icon-right {
            padding: var(--gdt-padding-control-icons-md);
        }

        gdt-button .gdt-button--size-md.gdt-button--icon:not(.gdt-button--icon-left, .gdt-button--icon-right) {
            padding: var(--gdt-padding-control-icon-only-md);
        }

        gdt-button .gdt-button--size-md .gdt-button__content {
            gap: var(--gdt-size-icon-gap-md);
        }

        gdt-button .gdt-button--size-sm {
            font-family: var(--gdt-typo-action-family);
            font-weight: var(--gdt-typo-action-weight-bold);
            font-size: var(--gdt-typo-action-size-sm);
            line-height: var(--gdt-typo-action-line-height-sm);
            min-width: var(--gdt-size-control-square-sm);
            padding: var(--gdt-padding-control-sm);
        }

        gdt-button .gdt-button--size-sm.gdt-button--icon-left {
            padding: var(--gdt-padding-control-icon-left-sm);
        }

        gdt-button .gdt-button--size-sm.gdt-button--icon-right {
            padding: var(--gdt-padding-control-icon-right-sm);
        }

        gdt-button .gdt-button--size-sm.gdt-button--icon-left.gdt-button--icon-right {
            padding: var(--gdt-padding-control-icons-sm);
        }

        gdt-button .gdt-button--size-sm.gdt-button--icon:not(.gdt-button--icon-left, .gdt-button--icon-right) {
            padding: var(--gdt-padding-control-icon-only-sm);
        }

        gdt-button .gdt-button--size-sm .gdt-button__content {
            gap: var(--gdt-size-icon-gap-sm);
        }

        gdt-button .gdt-button .gdt-button__content {
            display: inline-flex;
            align-items: center;
            justify-content: center;
            max-width: 100%;
        }

        .gdt-button-focusable {
            outline: none;
            --gdt-button-focusable-box-shadow: var(--gdt-shadow-focus-primary);
        }

        .gdt-button-focusable.gdt-button--appearance-primary-danger,
        .gdt-button-focusable.gdt-button--appearance-secondary-danger,
        .gdt-button-focusable:has(.gdt-button--appearance-primary-danger),
        .gdt-button-focusable:has(.gdt-button--appearance-secondary-danger) {
            --gdt-button-focusable-box-shadow: var(--gdt-shadow-focus-danger);
        }

        .gdt-button-focusable:focus {
            border-radius: var(--gdt-border-radius-component);
            box-shadow: var(--gdt-button-focusable-box-shadow);
        }
    </style>
    <style>
        gdt-checkbox {
            position: relative;
            display: inline-flex;
            border-radius: var(--gdt-border-radius-component);
            border: none;
            padding: var(--gdt-checkbox-padding);
        }

        gdt-checkbox.gdt-checkbox--focus {
            box-shadow: var(--gdt-shadow-focus-accent) !important;
        }

        gdt-checkbox:not(.gdt-checkbox--disabled) {
            cursor: pointer;
        }

        gdt-checkbox:not(.gdt-checkbox--disabled) label {
            cursor: pointer;
        }

        gdt-checkbox.gdt-checkbox--disabled {
            opacity: var(--gdt-opacity-disabled);
        }

        gdt-checkbox:hover:not(.gdt-checkbox--disabled) .gdt-checkbox__box {
            box-shadow: var(--gdt-shadow-1);
        }

        gdt-checkbox.gdt-checkbox--size-sm {
            font-family: var(--gdt-typo-action-family);
            font-weight: var(--gdt-typo-action-weight-bold);
            font-size: var(--gdt-typo-action-size-sm);
            line-height: var(--gdt-typo-action-line-height-sm);
            gap: var(--gdt-size-icon-gap-sm);
            --gdt-checkbox-box-size: 12px;
            --gdt-checkbox-box-margin: 2px;
        }

        gdt-checkbox.gdt-checkbox--size-md {
            font-family: var(--gdt-typo-action-family);
            font-weight: var(--gdt-typo-action-weight-bold);
            font-size: var(--gdt-typo-action-size-md);
            line-height: var(--gdt-typo-action-line-height-md);
            gap: var(--gdt-size-icon-gap-md);
            --gdt-checkbox-box-size: 15px;
            --gdt-checkbox-box-margin: 2.5px;
        }

        gdt-checkbox.gdt-checkbox--size-lg {
            font-family: var(--gdt-typo-action-family);
            font-weight: var(--gdt-typo-action-weight-bold);
            font-size: var(--gdt-typo-action-size-lg);
            line-height: var(--gdt-typo-action-line-height-lg);
            gap: var(--gdt-size-icon-gap-lg);
            --gdt-checkbox-box-size: 18px;
            --gdt-checkbox-box-margin: 3px;
        }

        gdt-checkbox.gdt-checkbox--checked {
            color: var(--gdt-color-accent-default);
        }

        gdt-checkbox.gdt-checkbox--checked:hover:not(.gdt-checkbox--disabled) {
            color: var(--gdt-color-accent-hover);
        }

        gdt-checkbox.gdt-checkbox--checked:hover:not(.gdt-checkbox--disabled) .gdt-checkbox__box {
            background-color: var(--gdt-color-accent-hover);
        }

        gdt-checkbox.gdt-checkbox--checked .gdt-checkbox__box {
            border: none;
            background-color: var(--gdt-color-accent-default);
        }

        gdt-checkbox.gdt-checkbox--checked .gdt-checkbox__box .gdt-checkbox__check-icon {
            visibility: visible;
        }

        gdt-checkbox .gdt-checkbox__box {
            box-sizing: border-box;
            display: flex;
            flex-shrink: 0;
            width: var(--gdt-checkbox-box-size);
            height: var(--gdt-checkbox-box-size);
            margin: var(--gdt-checkbox-box-margin);
            justify-content: center;
            align-items: center;
            border-radius: var(--gdt-border-radius-component);
            border: var(--gdt-border-regular) solid var(--gdt-color-border-default);
            background-color: var(--gdt-color-base-primary-default);
        }

        gdt-checkbox .gdt-checkbox__box .gdt-checkbox__check-icon {
            visibility: hidden;
            --gdt-icon-size: var(--gdt-checkbox-box-size);
        }

        gdt-checkbox.gdt-checkbox--appearance-button {
            outline: solid;
            outline-width: var(--gdt-border-regular);
            outline-offset: var(--gdt-border-offset-regular);
            outline-color: var(--gdt-color-border-default);
        }

        gdt-checkbox.gdt-checkbox--appearance-button:hover:not(.gdt-checkbox--disabled) {
            box-shadow: var(--gdt-shadow-1);
        }

        gdt-checkbox.gdt-checkbox--appearance-button.gdt-checkbox--checked {
            color: var(--gdt-color-accent-light-text);
            background-color: var(--gdt-color-accent-light-default);
            outline-width: var(--gdt-border-bold);
            outline-offset: var(--gdt-border-offset-bold);
            outline-color: var(--gdt-color-accent-default);
        }

        gdt-checkbox.gdt-checkbox--appearance-button.gdt-checkbox--checked:hover:not(.gdt-checkbox--disabled) {
            color: var(--gdt-color-accent-light-text);
            background-color: var(--gdt-color-accent-light-hover);
        }

        gdt-checkbox.gdt-checkbox--appearance-button.gdt-checkbox--checked .gdt-checkbox__box {
            background-color: var(--gdt-color-accent-light-text);
        }

        gdt-checkbox.gdt-checkbox--appearance-button.gdt-checkbox--size-sm {
            --gdt-checkbox-padding: var(--gdt-padding-control-sm);
