        .custom-tooltip {
            top: 2px;
            left: 3px;
            font-size: 18px;
            position: relative;
        }

        .custom-tooltip a span {
            color: gray;
        }

        .tooltip-main {
            width: auto;
            border-radius: 50%;
            font-weight: 700;
            background: #f3f3f3;
            border: 1px solid #737373;
            color: #737373;
        }

        .tooltip-inner {
            width: 300px;
            font-size: 1.2em;
            padding: 20px 15px 10px 20px;
            background: #fff;
            color: #000;
            border: 1px solid #737373;
            text-align: left;
        }

        @-webkit-keyframes fadeInFromNone {
            0% {
                display: none;
                opacity: 0;
            }

            1% {
                display: block;
                opacity: 0;
            }

            100% {
                display: block;
                opacity: 1;
            }
        }

        @-moz-keyframes fadeInFromNone {
            0% {
                display: none;
                opacity: 0;
            }

            1% {
                display: block;
                opacity: 0;
            }

            100% {
                display: block;
                opacity: 1;
            }
        }

        @-o-keyframes fadeInFromNone {
            0% {
                display: none;
                opacity: 0;
            }

            1% {
                display: block;
                opacity: 0;
            }

            100% {
                display: block;
                opacity: 1;
            }
        }

        @keyframes fadeInFromNone {
            0% {
                display: none;
                opacity: 0;
            }

            1% {
                display: block;
                opacity: 0;
            }

            100% {
                display: block;
                opacity: 1;
            }
        }

        @-webkit-keyframes alerteAnimation {
            from {
                margin-top: -80px;
            }

            to {
                margin-top: 0px;
            }
        }

        @-ms-keyframes alerteAnimation {
            from {
                margin-top: -80px;
            }

            to {
                margin-top: 0px;
            }
        }

        @keyframes alerteAnimation {
            from {
                margin-top: -80px;
            }

            to {
                margin-top: 0px;
            }
        }

        @-webkit-keyframes successAnimation {
            from {
                opacity: 0;
            }

            to {
                opacity: 1;
            }
        }

        @-ms-keyframes successAnimation {
            from {
                opacity: 0;
            }

            to {
                opacity: 1;
            }
        }

        @keyframes successAnimation {
            from {
                opacity: 0;
            }

            to {
                opacity: 1;
            }
        }

        #site-link a {
            margin: 0 5px;
        }

        .icon-tools {
            margin-bottom: 47px;
        }

        .wrapper,
        .wrapper-grc-selector,
        .wrapper-centered {
            float: inherit;
            max-width: 659px;
            padding: 20px;
            margin: 50px auto;
            border-radius: 10px;
            -webkit-animation: fadeInFromNone 0.5s ease-out;
            -moz-animation: fadeInFromNone 0.5s ease-out;
            -o-animation: fadeInFromNone 0.5s ease-out;
            animation: fadeInFromNone 0.5s ease-out;
        }

        .wrapper-centered {
            height: 100%;
            display: flex;
            justify-content: center;
            align-items: center;
            margin-top: 0;
            margin-bottom: 0;
            padding: 0;
        }

        @media (min-width: 1024px) {
            .wrapper-centered {
                max-width: 610px;
            }
        }

        @media (max-width: 1023px) {
            .wrapper-centered {
                max-width: 310px;
            }
        }

        .wrapper-grc-selector {
            height: 100%;
            display: flex;
            justify-content: center;
            align-items: center;
            margin-top: 0;
            margin-bottom: 0;
            padding: 0;
        }

        @media (min-width: 1024px) {
            .wrapper-grc-selector {
                max-width: 659px;
            }
        }

        @media (max-width: 1023px) {
            .wrapper-grc-selector {
                max-width: 341px;
                flex-direction: column;
            }
        }

        @media (max-width: 767px) {

            .wrapper,
            .wrapper-centered,
            .wrapper-grc-selector {
                padding: 5px;
            }
        }

        .form-group {
            display: inline-block;
            width: 100%;
        }

        #kc-form {
            display: block;
            height: 100%;
        }

        #kc-form-wrapper {
            width: 100%;
            margin-left: auto;
            margin-right: auto;
